#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m;
    cin>>n>>m;
    int a[n][m];
    for(int i=0;i<n;i++){
        for(int j=0;j<m;j++){
            cin>>a[i][j];
        }
    }
    int ans=0;
    for(int i=0;i<n;i++){
        for(int j=0;j<m;j++){
            for(int k=i;k<n;k++){
				for(int l=j;l<m;l++){
					int u=1;
					for(int o=i;o<=k;o++){
						for(int p=j;p<=l;p++){
							if(a[o][p]==0){
								u=0;
								break;
							}
						}
						if(u==0){
							break;
						}
					}
					if(u==1){
						ans=max(ans,(k-i+1)*(l-j+1));
					}
				}
			}
        }
    }
    cout<<ans;
    return 0;
}
